prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orgName WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Absgae")))

  ?choreo tai:belongsTo ?definitions .
  ?definitions tai:belongsTo ?model .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org rdfs:label ?orgName .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orgName ?taskName WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("absga")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("absge")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("absge")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("absgea"))
  )

  ?choreo tai:belongsTo ?definitions .
  ?definitions tai:belongsTo ?model .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org rdfs:label ?orgName .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
